export type EquipCategory =
  | 'weapon-simple'
  | 'weapon-martial'
  | 'armor'
  | 'gear'
  | 'tools'
  | 'potions'
  | 'packs'
  | 'mounts'
  | 'food'
  | 'life'

export type ArmorTier = 'light' | 'medium' | 'heavy' | 'shield'

export type MountTier = 'beast' | 'tack' | 'cart' | 'ship'

export const MOUNT_TIER_LABEL: Record<MountTier, string> = {
  beast: 'Ездовые животные и звери',
  tack: 'Упряжь и сёдла',
  cart: 'Сухопутный транспорт',
  ship: 'Корабли и лодки'
}

export type MasteryKey = 'cleave' | 'graze' | 'nick' | 'push' | 'sap' | 'slow' | 'topple' | 'vex'

