  w('life', 'Услуга — заклинатель 3 ур.', '50–150 зм', '—', 'Цена одного применения заклинания 3 уровня.'),
  w('life', 'Услуга — заклинатель 5 ур.', '250–500 зм', '—', 'Цена одного применения заклинания 5 уровня. На 6+ уровень цена резко растёт.')
